import { runWithBackoff } from "@1771technologies/js-utils";
import { BACKOFF_RUNS } from "../constants.js";
import { queryCell, queryFullWidthRow } from "../query.js";
import { handleFocus } from "./handle-focus.js";
export function handleFocusCellFromRoot({ scrollIntoView, done, gridId, viewport, cp, pos }, root) {
    if (!root)
        return;
    const nextIndex = root.rowIndex;
    if (root.kind === "full-width") {
        scrollIntoView({ row: nextIndex, behavior: "instant" });
        done();
        runWithBackoff(() => {
            return handleFocus(false, () => queryFullWidthRow(gridId, nextIndex, viewport), () => {
                cp.set((prev) => ({ ...prev, colIndex: pos.colIndex }));
            });
        }, BACKOFF_RUNS());
    }
    else {
        const { colIndex, rowIndex } = root.root ?? root;
        scrollIntoView({ row: rowIndex, column: colIndex, behavior: "instant" });
        done();
        runWithBackoff(() => {
            return handleFocus(false, () => queryCell(gridId, rowIndex, colIndex, viewport), () => {
                cp.set((prev) => ({ ...prev, colIndex: pos.colIndex }));
            });
        }, BACKOFF_RUNS());
    }
}
